{"code": "# Retry the 2 failed images
import requests
import base64
from PIL import Image
import io

NVIDIA_API_KEY = "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"
FLUX_ENDPOINT = "https://ai.api.nvidia.com/v1/genai/black-forest-labs/flux.2-klein-4b"

headers = {
    "Authorization": f"Bearer {NVIDIA_API_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json"
}

failed_prompts = [
    (15, "A space station orbiting a colorful nebula"),
    (25, "A grand piano in an abandoned concert hall")
]

def generate_image(prompt, output_path, seed=None):
    body = {
        "prompt": prompt,
        "cfg_scale": 1.0,
        "steps": 4,
        "width": 1024,
        "height": 1024,
        "seed": seed or 42
    }

    response = requests.post(FLUX_ENDPOINT, headers=headers, json=body, timeout=60)

    if response.status_code == 200:
        data = response.json()
        if 'artifacts' in data and len(data['artifacts']) > 0:
            img_base64 = data['artifacts'][0].get('base64', '')
            if img_base64:
                img_bytes = base64.b64decode(img_base64)
                img = Image.open(io.BytesIO(img_bytes))
                img.save(output_path)
                return True
    else:
        print(f"   Status: {response.status_code}, Response: {response.text[:100]}")
    return False

print("🔄 Retrying failed images...\n")
for num, prompt in failed_prompts:
    output_path = f"/home/z/flux_random_images/image_{num:02d}.png"
    print(f"[{num}/30] Retrying: {prompt[:40]}...", end=" ")

    try:
        if generate_image(prompt, output_path):
            print("✅ Success!")
        else:
            print("❌ Failed again")
    except Exception as e:
        print(f"❌ Error: {e}")

print("\n✅ Retry complete!")"}

